func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	// Preprocess all cells sorted by value
	cells := make([]Cell, 0, m*n)
	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			cells = append(cells, Cell{i, j, grid[i][j]})
		}
	}

	// Sort cells by value in descending order to allow efficient lookup of <= values
	// But for simplicity, we'll just iterate all cells when needed

	// Dijkstra's algorithm with state (i, j, k)
	visited := make([][][]int64, m)
	for i := range visited {
		visited[i] = make([][]int64, n)
		for j := range visited[i] {
			visited[i][j] = make([]int64, k+1)
			for l := range visited[i][j] {
				visited[i][j][l] = -1
			}
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &State{0, 0, k, 0})

	dirs := [][]int{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		curr := heap.Pop(&pq).(*State)
		i, j, currK, cost := curr.i, curr.j, curr.k, curr.cost

		if i == m-1 && j == n-1 {
			return cost
		}

		if visited[i][j][currK] != -1 && visited[i][j][currK] <= cost {
			continue
		}
		visited[i][j][currK] = cost

		// Try normal moves
		for _, dir := range dirs {
			ni, nj := i+dir[0], j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := cost + grid[ni][nj]
				if visited[ni][nj][currK] == -1 || newCost < visited[ni][nj][currK] {
					heap.Push(&pq, &State{ni, nj, currK, newCost})
				}
			}
		}

		// Try teleport if we have remaining k
		if currK > 0 {
			for _, cell := range cells {
				if cell.i == i && cell.j == j {
					continue
				}
				if cell.val <= grid[i][j] {
					ni, nj := cell.i, cell.j
					newK := currK - 1
