	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	// Directions: right and down
	dirs := [][]int{{0, 1}, {1, 0}}

	// Priority queue for Dijkstra's algorithm
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Cell{0, 0, 0, 0})

	// Visited matrix to keep track of minimum cost and steps
	visited := make([][][]int64, m)
	for i := range visited {
		visited[i] = make([][]int64, n)
		for j := range visited[i] {
			visited[i][j] = make([]int64, int(k)+1)
			for s := range visited[i][j] {
				visited[i][j][s] = -1
			}
		}
	}
	visited[0][0][0] = 0

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Cell)
		i, j := current.i, current.j
		currentCost := current.cost
		currentSteps := current.steps

		if i == m-1 && j == n-1 {
			return currentCost
		}

		if visited[i][j][currentSteps] != -1 && visited[i][j][currentSteps] < currentCost {
			continue
		}

		// Explore normal moves (right and down)
		for _, dir := range dirs {
			ni, nj := i+dir[0], j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := currentCost + grid[ni][nj]
				if visited[ni][nj][currentSteps] == -1 || newCost < visited[ni][nj][currentSteps] {
					visited[ni][nj][currentSteps] = newCost
					heap.Push(&pq, &Cell{ni, nj, newCost, currentSteps})
				}
			}
		}

		// Explore teleport moves if steps < k
		if currentSteps < int(k) {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if x == i && y == j {
						continue
					}
					if grid[x][y] <= grid[i][j] {
						newSteps := currentSteps + 1
						newCost := currentCost
						if visited[x][y][newSteps] == -1 || newCost < visited[x][y][newSteps] {
