func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	// Preprocess all cells sorted by value
	cells := make([]Cell, 0, m*n)
	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			cells = append(cells, Cell{i, j, grid[i][j]})
		}
	}
	// Sort cells by value in ascending order
	sort.Slice(cells, func(a, b int) bool {
		return cells[a].val < cells[b].val
	})

	// Dijkstra's algorithm
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &State{0, 0, k, 0})

