			for l := range visited[i][j] {
				visited[i][j][l] = -1
			}
		}
	}

	dirs := [][]int{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		curr := heap.Pop(&pq).(*State)
		if curr.i == m-1 && curr.j == n-1 {
			return curr.cost
		}
		if visited[curr.i][curr.j][curr.k] != -1 && visited[curr.i][curr.j][curr.k] <= curr.cost {
			continue
		}
		visited[curr.i][curr.j][curr.k] = curr.cost

		// Regular moves
		for _, dir := range dirs {
			ni, nj := curr.i+dir[0], curr.j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
