					heap.Push(&pq, &State{ni, nj, curr.k, newCost})
				}
			}
		}

		// Teleport moves
		if curr.k > 0 {
			// Binary search to find the first cell with value <= grid[curr.i][curr.j]
			left, right := 0, len(cells)-1
			best := -1
			target := grid[curr.i][curr.j]
			for left <= right {
				mid := left + (right-left)/2
				if cells[mid].val <= target {
					best = mid
					left = mid + 1
				} else {
