func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	// Directions for normal moves (right and down)
	dirs := [][]int{{0, 1}, {1, 0}}

	// Initialize a priority queue
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Cell{0, 0, 0, int(k)})

	// Create a visited matrix to keep track of the minimal cost and remaining steps
	visited := make([][][]int64, m)
	for i := range visited {
		visited[i] = make([][]int64, n)
		for j := range visited[i] {
			visited[i][j] = make([]int64, int(k)+1)
			for s := range visited[i][j] {
				visited[i][j][s] = math.MaxInt64
			}
		}
