		return cells[a].val < cells[b].val
	})

	// Create a map from cell (i,j) to its index in the sorted cells
	cellIndex := make([][]int, m)
	for i := range cellIndex {
		cellIndex[i] = make([]int, n)
	}
	for idx, cell := range cells {
		cellIndex[cell.i][cell.j] = idx
	}

	// Dijkstra's algorithm
	visited := make([][][]bool, m)
	for i := range visited {
		visited[i] = make([][]bool, n)
		for j := range visited[i] {
			visited[i][j] = make([]bool, k+1)
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &State{0, 0, k, 0})

	dirs := [][]int{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		curr := heap.Pop(&pq).(*State)
		i, j, currK, cost := curr.i, curr.j, curr.k, curr.cost

		if i == m-1 && j == n-1 {
			return cost
		}

		if visited[i][j][currK] {
			continue
		}
		visited[i][j][currK] = true

		// Try normal moves
		for _, dir := range dirs {
			ni, nj := i+dir[0], j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := cost + grid[ni][nj]
				if !visited[ni][nj][currK] {
					heap.Push(&pq, &State{ni, nj, currK, newCost})
				}
			}
		}

		// Try teleport if possible
		if currK > 0 {
			// Find all cells with value <= grid[i][j]
			// Using binary search to find the upper bound
			targetVal := grid[i][j]
			left, right := 0, len(cells)
			for left < right {
				mid := left + (right-left)/2
				if cells[mid].val <= targetVal {
					left = mid + 1
				} else {
					right = mid
				}
			}
			// All cells before left have value <= targetVal
			for idx := 0; idx < left; idx++ {
				cell := cells[idx]
				ni, nj := cell.i, cell.j
				if ni == i && nj == j {
					continue
				}
				if !visited[ni][nj][currK-1] {
					heap.Push(&pq, &State{ni, nj, currK - 1, cost})
				}
			}
		}
	}

	return -1
