import (
	"container/heap"
	"math"
)

type Cell struct {
	i, j, k int
	cost    int64
}

type PriorityQueue []*Cell

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}
func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}
func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Cell)
	*pq = append(*pq, item)
}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	maxK := int(k)
	dirs := [][]int{{0, 1}, {1, 0}}

	// Initialize cost matrix with infinity
	cost := make([][][]int64, m)
	for i := range cost {
		cost[i] = make([][]int64, n)
		for j := range cost[i] {
			cost[i][j] = make([]int64, maxK+1)
			for l := range cost[i][j] {
				cost[i][j][l] = math.MaxInt64
			}
		}
	}
	cost[0][0][maxK] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Cell{0, 0, maxK, 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Cell)
		i, j, currentK, currentCost := current.i, current.j, current.k, current.cost

		if i == m-1 && j == n-1 {
			return currentCost
		}

		if currentCost > cost[i][j][currentK] {
			continue
		}

		// Try normal moves
		for _, dir := range dirs {
			ni, nj := i+dir[0], j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := currentCost + grid[ni][nj]
				if newCost < cost[ni][nj][currentK] {
					cost[ni][nj][currentK] = newCost
					heap.Push(&pq, &Cell{ni, nj, currentK, newCost})
				}
			}
		}

		// Try teleport if remaining teleports
		if currentK > 0 {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if x == i && y == j {
						continue
					}
					if grid[x][y] <= grid[i][j] {
						newK := currentK - 1
						if currentCost < cost[x][y][newK] {
							cost[x][y][newK] = currentCost
							heap.Push(&pq, &Cell{x, y, newK, currentCost})
						}
					}
				}
			}
		}
	}

	// Find the minimal cost among all possible k's at (m-1, n-1)
	minCost := int64(math.MaxInt64)
	for _, c := range cost[m-1][n-1] {
		if c < minCost {
			minCost = c
		}
	}
	return minCost
}
