			}
		}

		// Teleport moves
		if teleports > 0 {
			for ti := 0; ti < m; ti++ {
				for tj := 0; tj < n; tj++ {
					if (ti != i || tj != j) && grid[ti][tj] <= grid[i][j] {
						newTeleports := teleports - 1
						if visited[ti][tj][newTeleports] == -1 || cost < visited[ti][tj][newTeleports] {
							heap.Push(&pq, &Cell{ti, tj, cost, newTeleports})
						}
					}
				}
			}
		}
	}

	return -1
}
