	"math"
)

type Cell struct {
	i, j, k int
	cost    int64
}

type PriorityQueue []*Cell

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}
func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}
func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Cell)
	*pq = append(*pq, item)
}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	maxK := int(k)
	dirs := [][]int{{0, 1}, {1, 0}}

	// Initialize cost matrix with infinity
	cost := make([][][]int64, m)
	for i := range cost {
		cost[i] = make([][]int64, n)
		for j := range cost[i] {
			cost[i][j] = make([]int64, maxK+1)
			for l := range cost[i][j] {
				cost[i][j][l] = math.MaxInt64
			}
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Cell{0, 0, maxK, 0})
	cost[0][0][maxK] = 0

	for pq.Len() > 0 {
		curr := heap.Pop(&pq).(*Cell)
		if curr.i == m-1 && curr.j == n-1 {
			return curr.cost
		}
		if curr.cost > cost[curr.i][curr.j][curr.k] {
			continue
		}

		// Try normal moves
		for _, dir := range dirs {
			ni, nj := curr.i+dir[0], curr.j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := curr.cost + grid[ni][nj]
				if newCost < cost[ni][nj][curr.k] {
					cost[ni][nj][curr.k] = newCost
					heap.Push(&pq, &Cell{ni, nj, curr.k, newCost})
				}
			}
		}

		// Try teleport if remaining k > 0
		if curr.k > 0 {
			for i := 0; i < m; i++ {
				for j := 0; j < n; j++ {
					if i == curr.i && j == curr.j {
						continue
					}
					if grid[i][j] <= grid[curr.i][curr.j] {
						newK := curr.k - 1
						if curr.cost < cost[i][j][newK] {
							cost[i][j][newK] = curr.cost
							heap.Push(&pq, &Cell{i, j, newK, curr.cost})
						}
					}
				}
			}
		}
	}

	// Find the minimal cost among all possible k's at (m-1, n-1)
	minCost := int64(math.MaxInt64)
	for _, c := range cost[m-1][n-1] {
		if c < minCost {
			minCost = c
		}
	}
	return minCost
}
