	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	// Directions for normal moves (right and down)
	dirs := [][]int{{0, 1}, {1, 0}}

	// Initialize a priority queue
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Cell{0, 0, 0, k})

	// Create a visited matrix to keep track of the minimum cost and remaining teleports
	visited := make([][][]int64, m)
	for i := range visited {
		visited[i] = make([][]int64, n)
		for j := range visited[i] {
			visited[i][j] = make([]int64, k+1)
			for t := range visited[i][j] {
				visited[i][j][t] = math.MaxInt64
			}
		}
	}
	visited[0][0][k] = 0

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Cell)
		i, j := current.i, current.j
		currentCost := current.cost
		remainingTeleports := current.teleports

		if i == m-1 && j == n-1 {
			return currentCost
		}

		if currentCost > visited[i][j][remainingTeleports] {
			continue
		}

		// Normal moves (right and down)
		for _, dir := range dirs {
			ni, nj := i+dir[0], j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := currentCost + grid[ni][nj]
				if newCost < visited[ni][nj][remainingTeleports] {
					visited[ni][nj][remainingTeleports] = newCost
					heap.Push(&pq, &Cell{ni, nj, newCost, remainingTeleports})
				}
			}
		}

		// Teleport move if remaining teleports > 0
		if remainingTeleports > 0 {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if x == i && y == j {
						continue
					}
					if grid[x][y] <= grid[i][j] {
						newCost := currentCost
						newTeleports := remainingTeleports - 1
						if newCost < visited[x][y][newTeleports] {
							visited[x][y][newTeleports] = newCost
							heap.Push(&pq, &Cell{x, y, newCost, newTeleports})
						}
					}
				}
			}
		}
	}

	return -1
}
